import myOpenGL     from '../../myOpenGL.js'

// ==========================================
// 1. HÀM PHÂN TÍCH FILE MARKDOWN (MD PARSER)
// ==========================================
const parseQuizMarkdown = (mdText) => {
  const questions = [];
  
  // Cắt nội dung text thành các khối dựa trên thẻ "### Câu 1", "### Câu 2"...
  const blocks = mdText.split(/###\s*Câu\s*\d+/i);

  blocks.forEach(block => {
    if (!block.trim()) return;

    const lines = block.trim().split('\n');
    let questionText = "";
    let choices = [];

    lines.forEach(line => {
      // Tìm các dòng bắt đầu bằng "* A.", "* B.", "* C.", "* D."
      const match = line.match(/^\*\s*[A-D]\.\s*(.*)/);
      if (match) {
        let text = match[1].trim();
        let isCorrect = false;
        
        // BÍ QUYẾT: Nếu cuối dòng có chữ (Đúng), hệ thống sẽ ghi nhận đây là đáp án chuẩn
        if (text.includes('(Đúng)')) {
          isCorrect = true;
          text = text.replace('(Đúng)', '').trim();
        }
        
        choices.push({ text: text, isCorrect: isCorrect });
      } else {
        // Nếu không phải đáp án thì nó là nội dung câu hỏi
        questionText += line + "\n";
      }
    });

    // Chỉ đưa vào danh sách nếu khối này lấy ra được các đáp án
    if (choices.length > 0) {
      questions.push({
        question: questionText.trim(),
        choices: choices
      });
    }
  });

  return questions;
};

// window._shader_btn_click = _shader_btn_click;

export default async function(Module, entityId, C, API) {
  var e = window.App.entities[window.App.C.GetEntityName(entityId)];
  const speakerName = e.name;

  if (!e.mathQuestion || !e.mathQuestion.endsWith('.md')) {
    console.error("Entity này không có file Markdown câu hỏi!");
    return false;
  }

  // 1. Đọc file MD và Parse câu hỏi
  const mdContent = await window.readMarkdownFile(e.mathQuestion);
  const allQuestions = parseQuizMarkdown(mdContent);

  if (allQuestions.length === 0) {
    console.error("Không tìm thấy câu hỏi nào trong file MD!");
    return false;
  }

  if (!e.npcProgress.isCompleted) {
    e.state = window.App.C.STATE_IDLE;
  }

  // ==========================================
  // VÒNG LẶP TRẠNG THÁI (STATE MACHINE)
  // ==========================================
  let currentState = "TEACHING"; 
  let isInteracting = true;
  let randomIndex = Math.floor(Math.random() * allQuestions.length);

  while (isInteracting) {

    // --- 1. KIỂM TRA ĐIỀU KIỆN CHIẾN THẮNG ---
    if (e.npcProgress.solved >= e.npcProgress.total) {
      // if (cv) cv.style.display = 'none';
      window.SpeakText("Chúc mừng bé đã hoàn thành xuất sắc!", 'vi-VN', 1.0, 1.2);
      await API.Say(entityId, speakerName, "### 🎉 Nhiệm vụ hoàn thành!\n\nBé đã giải quyết xong toàn bộ thử thách toán học hôm nay rồi. Giỏi lắm!");
      break; // Thoát vòng lặp, kết thúc kịch bản
    }

    // ------------------------------------------------
    // TRẠNG THÁI A: LỚP HỌC (Đọc lý thuyết)
    // ------------------------------------------------
    if (currentState === "TEACHING") {
      // if (cv) cv.style.display = 'none'; // Ẩn hình ảnh 3D/Canvas khi đang học lý thuyết

      // 💡 Mẹo: Nếu mdContent chứa cả đề trắc nghiệm, bạn có thể cắt chuỗi để chỉ hiện phần lý thuyết ở trên cùng.
      const teachingContent = "### 📚 Bài Học Toán\n\n" + mdContent; 
      
      const selectedIdx = await API.Ask(entityId, speakerName, teachingContent, ["✏️ Làm bài tập", "❌ Thoát"]);
      
      if (selectedIdx === 0) {
        currentState = "PRACTICE"; 
      } else {
        isInteracting = false; // Chọn thoát hoặc tắt ngang
      }
    } 

    // ------------------------------------------------
    // TRẠNG THÁI B: THỰC HÀNH (Trắc nghiệm ngẫu nhiên)
    // ------------------------------------------------
    else if (currentState === "PRACTICE") {
      // if (cv) cv.style.display = 'block'; // Hiện Canvas 3D/Shader để minh họa câu hỏi

      const mathProblem = allQuestions[randomIndex];
      console.log(`Đang làm câu hỏi số: ${randomIndex}`);

      // Xáo trộn vị trí các đáp án (A, B, C, D)
      const shuffledChoices = [...mathProblem.choices].sort(() => Math.random() - 0.5);
      const choiceTexts = shuffledChoices.map((c, index) => {
        const prefix = String.fromCharCode(65 + index); // Tạo A., B., C.
        return `${prefix}. ${c.text}`;
      });

      // THÊM LỰA CHỌN QUAY VỀ: Nút luôn nằm ở cuối cùng
      choiceTexts.push("🔙 Xem lại bài học");

      const displayQuestion = `### 🧮 Thử thách Toán Học! (${e.npcProgress.solved}/${e.npcProgress.total})\n\n${mathProblem.question}`;

      // Gọi hộp thoại
      const selectedIdx = await API.Ask(entityId, speakerName, displayQuestion, choiceTexts);

      if (selectedIdx === -1) {
        isInteracting = false; // Tắt chéo hộp thoại
        break;
      }

      // NẾU CHỌN "QUAY LẠI BÀI HỌC" (Nút cuối)
      if (selectedIdx === choiceTexts.length - 1) {
        currentState = "TEACHING";
        continue; // Bỏ qua phần check đáp án bên dưới, nhảy thẳng lại vòng lặp Teaching
      }

      // KHI BÉ CHỌN ĐÁP ÁN TOÁN:
      const selectedChoice = shuffledChoices[selectedIdx];

      if (selectedChoice.isCorrect) {
        window.TriggerFeedback(true);
        window.UpdateQuestProgress(entityId, true); 
        window.SpeakText("Chính xác! Bé giỏi quá!", 'vi-VN', 1.0, 1.2);
        await API.Say(entityId, speakerName, "### 🎉 Chính xác!\n\nBé giải quá chuẩn luôn!");
        
        // Chỉ khi trả lời đúng mới random câu tiếp theo
        randomIndex = Math.floor(Math.random() * allQuestions.length); 

      } else {
        window.TriggerFeedback(false);
        window.SpeakText("Ôi, chưa đúng rồi. Bé thử lại nhé!", 'vi-VN', 1.0);
        await API.Say(entityId, speakerName, "### ❌ Chưa đúng mất rồi!\n\nBé hãy đọc kỹ lại đề bài và tính toán lại xem sao nhé!");
        // Không đổi randomIndex, ép bé làm lại câu này cho đến khi đúng
      }
    }
  }

  // Dọn dẹp an toàn khi tắt
  return true;
}
